// ============================================
// استخراج وتنظيف البيانات من الـ AI Agent
// ============================================

// 1. جيب الرد من الـ AI Agent
let response = '';
try {
  // جرب تجيب الـ output من الـ AI Agent
  const aiData = $('AI Agent').item.json;
  response = aiData.output || aiData.text || aiData.content || JSON.stringify(aiData);
} catch (e) {
  // لو فشل، جرب من الـ input الحالي
  response = $json.output || $json.text || $json.content || JSON.stringify($json);
}

if (typeof response !== 'string') {
  response = JSON.stringify(response);
}

// 2. جيب الـ Memory
let memory = [];
try {
  memory = $('AI Agent').item.json.memory || [];
} catch (e) {
  console.log('⚠️ No memory available');
}

// 3. جيب Chat ID
let chatId = 'unknown';
try {
  chatId = $('Telegram Trigger').item.json.message?.chat?.id || 
           $('AI Agent').item.json.chatId ||
           $json.chatId ||
           'unknown';
} catch (e) {
  console.log('⚠️ No chat ID found');
}

console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
console.log('📥 INPUT DATA');
console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
console.log('Chat ID:', chatId);
console.log('Response:', response.substring(0, 200));
console.log('Memory Length:', memory.length);

// ============================================
// دالة البحث عن JSON
// ============================================
function findJSON(text) {
  if (!text || typeof text !== 'string') return null;

  const patterns = [
    /\{\s*"status"\s*:\s*"completed"[^}]*"name"[^}]*"department"[^}]*"request_type"[^}]*"category"[^}]*\}/gi,
    /\{[^}]*"status"\s*:\s*"completed"[^}]*\}/gi,
    /\{[^}]*"name"[^}]*"department"[^}]*"request_type"[^}]*"category"[^}]*\}/gi
  ];

  for (const pattern of patterns) {
    const matches = text.match(pattern);
    if (matches) {
      for (const match of matches) {
        try {
          const cleanMatch = match.replace(/[\u0000-\u001F\u007F-\u009F]/g, '').trim();
          const parsed = JSON.parse(cleanMatch);
          if (parsed.status === 'completed' || (parsed.name && parsed.department)) {
            return parsed;
          }
        } catch (e) {
          continue;
        }
      }
    }
  }
  return null;
}

// ============================================
// ابحث عن البيانات
// ============================================
let extractedData = null;
let dataSource = 'none';

// في الرد الحالي
console.log('🔍 Searching current response...');
extractedData = findJSON(response);
if (extractedData) {
  dataSource = 'current_response';
  console.log('✅ Found in response');
}

// في الـ Memory
if (!extractedData && memory.length > 0) {
  console.log('🔍 Searching memory...');
  for (let i = memory.length - 1; i >= 0; i--) {
    const content = memory[i].content || memory[i].text || '';
    extractedData = findJSON(content);
    if (extractedData) {
      dataSource = `memory[${i}]`;
      console.log(`✅ Found in memory[${i}]`);
      break;
    }
  }
}

// ============================================
// نضّف وتحقق من البيانات
// ============================================
if (extractedData) {
  console.log('📦 Raw data:', JSON.stringify(extractedData, null, 2));

  const cleanData = {
    status: 'completed',
    name: (extractedData.name || '').trim(),
    department: (extractedData.department || '').trim(),
    request_type: (extractedData.request_type || '').trim(),
    category: (extractedData.category || '').trim(),
    details: (extractedData.details || extractedData.description || 'لا يوجد').trim()
  };

  // نضّف التفاصيل الفارغة
  if (!cleanData.details || 
      cleanData.details === '' || 
      cleanData.details.toLowerCase() === 'none' ||
      cleanData.details === 'null') {
    cleanData.details = 'لا يوجد';
  }

  // تحقق من الحقول
  const requiredFields = ['name', 'department', 'request_type', 'category'];
  const missingFields = requiredFields.filter(f => !cleanData[f] || cleanData[f].length === 0);
  const isValid = missingFields.length === 0;

  console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  console.log('✨ CLEAN DATA');
  console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  console.log('Valid:', isValid);
  console.log('Missing:', missingFields.join(', ') || 'none');
  console.log('Data:', JSON.stringify(cleanData, null, 2));

  if (isValid) {
    cleanData.chat_id = chatId;
    cleanData.timestamp = new Date().toISOString();
    cleanData.date = new Date().toLocaleString('ar-EG', { timeZone: 'Africa/Cairo' });
    cleanData.data_source = dataSource;

    console.log('✅ READY TO SAVE');

    return [{
      json: {
        ...cleanData,
        ready_for_sheet: true,
        ready_for_trello: true
      }
    }];
  } else {
    console.log('❌ INCOMPLETE');
    return [{
      json: {
        status: 'incomplete',
        ready_for_sheet: false,
        ready_for_trello: false,
        extracted_data: cleanData,
        missing_fields: missingFields,
        output: response
      }
    }];
  }
}

// ============================================
// لسه بيكلم المستخدم
// ============================================
console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
console.log('💬 STILL CHATTING');
console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

return [{
  json: {
    status: 'chatting',
    ready_for_sheet: false,
    ready_for_trello: false,
    output: response,
    chat_id: chatId
  }
}];

const cb = $json.callback_query || $json;

console.log('callback data string:', cb.data);

if (!cb || !cb.data) {
  console.log('مفيش callback_query!');
  return [];
}

const parts = cb.data.split('_');
const rating = Number(parts[1]);
const cardId = parts.slice(2).join('_');

return {
  json: {
    rating,
    cardId,
    chatId: cb.message?.chat?.id || cb.chat?.id,
    messageId: cb.message?.message_id, // ← ضيف message ID
    callbackQueryId: cb.id,
    user: cb.from?.username || cb.from?.first_name,
    timestamp: new Date().toISOString(),
    Rating_sent: 'TRUE'
  }
};

const item = $json;

const chatId =
  item.message?.chat?.id ??
  item.callback_query?.message?.chat?.id ??
  null;

const user_message =
  item.message?.text ??
  item.callback_query?.data ??
  "";

return [{
  json: {
    chatId,
    user_message
  }
}];

const rows = $input.all();
const userMessage = $('Telegram Trigger').first().json.message?.text;
const chatId = $('Telegram Trigger').first().json.message?.chat?.id;

if (rows.length === 0) {
  return [{
    json: {
      route: 'ai_agent',
      chatId,
      user_message: userMessage
    }
  }];
}

// نجيب أحدث صف فقط
rows.sort((a, b) => b.json.row_number - a.json.row_number);
const latest = rows[0];

// تنظيف القيم
const waiting = String(latest.json['Waiting_feedback'] || '')
  .trim()
  .toLowerCase();

const ratingRaw = latest.json['التقييم'];
const rate =
  ratingRaw !== undefined && ratingRaw !== ''
    ? Number(ratingRaw)
    : null;

// الشرط الآمن
if (waiting === 'pending' && rate !== null && rate < 4) {
  return [{
    json: {
      route: 'save_feedback',
      chatId,
      Cardid: latest.json['Cardid'],
      feedback: userMessage
    }
  }];
}

// غير كده → رسالة عادية
return [{
  json: {
    route: 'ai_agent',
    chatId,
    user_message: userMessage
  }
}];

