const data = $json;

// ===============================
// بيانات المستخدم من Telegram Trigger
// ===============================
const tg = $items('Telegram Trigger')[0].json.message;

const chatId = tg.chat.id;
const firstName = tg.chat.first_name || '';
const lastName = tg.chat.last_name || '';
const userName = tg.chat.username
  ? `@${tg.chat.username}`
  : `${firstName} ${lastName}`;

// ===============================
// تاريخ بداية الطلب (تاريخ فقط)
// فورمات: 14/Jan/2026
// ===============================
const start_date = new Date().toLocaleDateString('en-GB', {
  timeZone: 'Africa/Cairo',
  day: '2-digit',
  month: 'short',
  year: 'numeric',
}).replace(/ /g, '/');

// ===============================
// 1️⃣ Description لتريلو (زي الصورة)
// ===============================
const trello_description = `
${data.name}
${data.department}
Issue: ${data.request_type}
${data.details}

Chat ID : @${chatId}
First Name : ${firstName}
Last Name : ${lastName}
User Name : ${userName}
`.trim();

// ===============================
// 2️⃣ شكل البيانات لجوجل شيت
// ===============================
const sheet_issue = `Chat ID : @${chatId} | ${data.department} | Issue: ${data.request_type}`;

// ===============================
// Output النهائي
// ===============================
return [
  {
    json: {
      // مشترك
      name: data.name,
      department: data.department,
      request_type: data.request_type,
      category: data.category,
      details: data.details,
      ready_for_trello: data.ready_for_trello,

      // ✅ تاريخ بداية الطلب
      start_date,

      // Trello
      trello_description,

      // Google Sheet
      sheet_issue,
      sheet_owner: data.name,

      // Telegram
      chatId,
      firstName,
      lastName,
      userName,
    }
  }
];

// نرجع البيانات عادي
return [{
  json: {
    chatId: $('Code Rate').item.json.chatId,
    cardId: $('Code Rate').item.json.cardId,
    rating: $('Code Rate').item.json.rating
  }
}];

